(function () {
    'use strict';
    const root = document.querySelector('[data-vh360-studio-mobile-live]');
    const cfg = window.vh360StudioMobileLive || window.vh360StudioDashboard || {};
    if (!root) { return; }
    try { localStorage.setItem('vh360StudioMode', 'mobile'); } catch (e) {}
    const $ = (s) => root.querySelector(s);
    const $$ = (s) => Array.prototype.slice.call(root.querySelectorAll(s));
    const state = { name: 'setup', session: null, videoId: 0, viewerUrl: '', heartbeat: 0, duration: 0, durationTimer: 0, goLiveBusy: false, endBusy: false, mutedAudio: false, mutedVideo: false, facingMode: 'user', wakeLock: null, coverId: 0 };
    function api(path, options) { return fetch((cfg.restRoot || '').replace(/\/$/, '') + path, options).then(async r => { const j = await r.json().catch(() => ({})); if (!r.ok) { throw new Error(j.message || 'Request failed'); } return j; }); }
    function setStatus(msg) { const el = $('[data-mobile-status]'); if (el) { el.textContent = msg; } }
    function setState(next) { state.name = next; $$('[data-mobile-stage]').forEach(el => el.classList.toggle('is-active', el.dataset.mobileStage === next)); }
    function formPayload() { return { title: ($('[data-mobile-title]') || {}).value || '', description: ($('[data-mobile-description]') || {}).value || '', chat_enabled: $('[data-mobile-chat]').checked, viewer_count: $('[data-mobile-viewer-count]').checked, agora_mode: $('[data-mobile-agora-mode]').value, agora_everyone_is_host: $('[data-mobile-everyone-host]').checked, require_passcode: $('[data-mobile-require-passcode]').checked, host_passcode: $('[data-mobile-host-passcode]').value, featured_image_id: state.coverId, recording_intent: 'none' }; }
    async function uploadCover() { const input = $('[data-mobile-cover]'); if (!input || !input.files || !input.files[0]) { return 0; } const fd = new FormData(); fd.append('cover_image', input.files[0]); const res = await api('/cover-image', { method: 'POST', headers: { 'X-WP-Nonce': cfg.nonce }, body: fd }); state.coverId = res.id || res.attachment_id || res.featured_image_id || 0; return state.coverId; }
    async function preview() { if (state.session) { return; } setState('requesting_permissions'); setStatus('Requesting camera and microphone permissions…'); state.session = window.VH360AgoraBroadcaster.create({ container: root, localContainer: $('[data-agora-local-preview]'), videoConfig: cfg.mobileVideoConfig || { facingMode: 'user', encoderConfig: { width: 1280, height: 720, frameRate: 30, bitrateMin: 800, bitrateMax: 1800 }, optimizationMode: 'motion' }, audioConfig: cfg.mobileAudioConfig || {}, renewalEndpoint: function (videoId) { return '/broadcasts/' + videoId + '/renew-token'; }, renewToken: renewToken }); await state.session.prepareMedia(); setState('preview_ready'); setStatus('Camera preview is ready.'); }
    async function renewToken() { if (!state.videoId) { return null; } return api('/broadcasts/' + state.videoId + '/renew-token', { method: 'POST', headers: { 'Content-Type': 'application/json', 'X-WP-Nonce': cfg.nonce } }); }
    function startHeartbeat() { stopHeartbeat(); state.heartbeat = setInterval(() => { if (state.videoId && (state.name === 'live' || state.name === 'reconnecting')) { api('/broadcasts/' + state.videoId + '/heartbeat', { method: 'POST', headers: { 'Content-Type': 'application/json', 'X-WP-Nonce': cfg.nonce } }).catch(() => {}); } }, 30000); }
    function stopHeartbeat() { if (state.heartbeat) { clearInterval(state.heartbeat); state.heartbeat = 0; } }
    function startDuration() { const start = Date.now(); clearInterval(state.durationTimer); state.durationTimer = setInterval(() => { const s = Math.floor((Date.now() - start) / 1000); const m = String(Math.floor(s / 60)).padStart(2, '0'); const ss = String(s % 60).padStart(2, '0'); $$('[data-mobile-duration]').forEach(el => el.textContent = m + ':' + ss); }, 1000); }
    async function requestWakeLock() { if (navigator.wakeLock && navigator.wakeLock.request) { try { state.wakeLock = await navigator.wakeLock.request('screen'); } catch (e) {} } }
    async function releaseWakeLock() { if (state.wakeLock && state.wakeLock.release) { await state.wakeLock.release().catch(() => {}); } state.wakeLock = null; }
    async function goLive() { if (state.goLiveBusy) { return; } const payload = formPayload(); if (!payload.title.trim()) { setStatus('Enter a title before going live.'); return; } if (!state.session) { setStatus('Preview your camera before going live.'); return; } state.goLiveBusy = true; try { setState('creating_broadcast'); setStatus('Creating livestream…'); await uploadCover(); Object.assign(payload, { featured_image_id: state.coverId }); const created = await api('/broadcasts', { method: 'POST', headers: { 'Content-Type': 'application/json', 'X-WP-Nonce': cfg.nonce }, body: JSON.stringify(payload) }); const b = created.broadcast || {}; state.videoId = b.videoId; state.viewerUrl = b.viewerPermalink || ''; setStatus('Connecting to Agora…'); const prepared = await api('/broadcasts/' + state.videoId + '/prepare', { method: 'POST', headers: { 'Content-Type': 'application/json', 'X-WP-Nonce': cfg.nonce } }); await state.session.connect(Object.assign({}, prepared, { videoId: state.videoId })); await api('/broadcasts/' + state.videoId + '/started', { method: 'POST', headers: { 'Content-Type': 'application/json', 'X-WP-Nonce': cfg.nonce }, body: JSON.stringify({ job_id: 0 }) }); $$('[data-mobile-open-viewer],[data-mobile-open-video]').forEach(a => { if (state.viewerUrl) { a.href = state.viewerUrl; } }); $('[data-mobile-live-preview]').appendChild($('[data-agora-local-preview]')); setState('live'); setStatus('You are live. Keep this browser open.'); startHeartbeat(); startDuration(); requestWakeLock(); } catch (e) { setState('preview_ready'); setStatus(e.message || 'Could not start live.'); } finally { state.goLiveBusy = false; } }
    async function endLive() { if (state.endBusy || !state.videoId) { return; } if (!window.confirm('End this livestream?')) { return; } state.endBusy = true; setState('ending'); setStatus('Ending livestream…'); stopHeartbeat(); clearInterval(state.durationTimer); try { if (state.session) { await state.session.stop(); } await api('/broadcasts/' + state.videoId + '/end', { method: 'POST', headers: { 'Content-Type': 'application/json', 'X-WP-Nonce': cfg.nonce } }); await releaseWakeLock(); setState('ended'); setStatus('Livestream ended.'); } catch (e) { setState('end_failed'); setStatus('Local stream stopped, but the server did not confirm End Live. Use End Live Again.'); } finally { state.endBusy = false; } }
    function bind() { $('[data-mobile-preview]').addEventListener('click', preview); $('[data-mobile-go-live]').addEventListener('click', goLive); $('[data-mobile-back-setup]').addEventListener('click', () => setState('setup')); $$('[data-mobile-end-live]').forEach(b => b.addEventListener('click', endLive)); $$('[data-mobile-switch-camera]').forEach(b => b.addEventListener('click', async () => { state.facingMode = state.facingMode === 'user' ? 'environment' : 'user'; if (state.session) { await state.session.switchCamera(state.facingMode).catch(e => setStatus(e.message)); } })); $$('[data-mobile-mute-audio]').forEach(b => b.addEventListener('click', async () => { state.mutedAudio = !state.mutedAudio; if (state.session) { await state.session.muteAudio(state.mutedAudio); } b.textContent = state.mutedAudio ? 'Unmute mic' : 'Mute mic'; })); $$('[data-mobile-mute-video]').forEach(b => b.addEventListener('click', async () => { state.mutedVideo = !state.mutedVideo; if (state.session) { await state.session.muteVideo(state.mutedVideo); } b.textContent = state.mutedVideo ? 'Camera on' : 'Camera off'; })); $('[data-mobile-start-another]').addEventListener('click', () => window.location.href = window.location.href); window.addEventListener('beforeunload', function (e) { if (['connecting','live','reconnecting','ending'].indexOf(state.name) !== -1) { e.preventDefault(); e.returnValue = ''; } }); window.addEventListener('pagehide', function () { if (state.videoId && ['live','reconnecting','ending'].indexOf(state.name) !== -1) { navigator.sendBeacon && navigator.sendBeacon((cfg.restRoot || '').replace(/\/$/, '') + '/broadcasts/' + state.videoId + '/end?_wpnonce=' + encodeURIComponent(cfg.nonce), new Blob([], { type: 'application/json' })); } }); root.addEventListener('vh360:agora-broadcaster:connection-state-change', e => { const c = e.detail.current || ''; $$('[data-mobile-connection]').forEach(el => el.textContent = c); if (c === 'RECONNECTING') { setState('reconnecting'); } else if (c === 'CONNECTED' && state.videoId) { setState('live'); } }); root.addEventListener('vh360:agora-broadcaster:track-ended', e => setStatus((e.detail.kind || 'Media') + ' disconnected. Check permissions or devices.')); }
    bind();
})();
